  ('elementary-8b44517b-moex-00457', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '有關勞動檢查方針的敘述，下列何者正確？', '["勞動檢查方針之制定，應參酌勞動條件現況、安全衛生條件、職業傷病頻率之情況", "於年度開始前六個月公告並宣導", "勞動檢查機構應於檢查方針公告後二個月內，擬定勞動監督檢查計畫", "其內容有優先受檢查事業單位之名單"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00458', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '對於勞動檢查的結果，依法應如何處理？', '["告知雇主及工會", "若有違反勞動法令規定事項者，勞動檢查機構並應於十日內以書面通知事業單位立即改正或限期改善", "事業單位應於違規場所顯明易見處公告十日以上", "應報由勞動部依法處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00459', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '工會法定列舉的任務中，不包括下列那個項目？', '["就業服務事業之舉辦", "勞資爭議之處理", "會員康樂事項之舉辦", "勞工統計之編製"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00460', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '工會召開會員大會或會員代表大會，依法會議開始進行後，有出席人數二分之一以上即可議決的事項， 不包括下列何者？', '["工會各項經費收繳數額、經費之收支預算", "基金之運用及處分", "財產之處分", "集體勞動條件之維持或變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00461', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '為保護工會活動，雇主從事下列何項違法行為，經命限期改正，屆期未改正，依法得按次連續處罰？', '["不准工會理監事請公假辦理會務", "對於勞工或求職者以不加入工會或擔任工會職務為僱用條件", "對於勞工參與爭議行為，而解僱或為其他不利之待遇", "對於勞工提出團體協商之要求，而拒絕僱用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00462', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列何事業機構之團體協約，應於簽訂前取得核可，未經核可者，無效？', '["醫療事業機構", "金融事業機構", "交通事業機構", "公營事業機構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00463', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '我國團體協約得約定雇主以僱用一定工會之會員為限。但有下列何種情形，依法不受限制？', '["雇主引進新技術所需專門之人", "雇主僱用為其管理財務之人", "雇主僱用高科技人才", "雇主僱用人事主管"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00464', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '我國團體協約法第19條之規定，下列敘述何者正確？', '["勞動契約異於該團體協約所約定之勞動條件者，其相異部分無效", "勞動契約無效之部分，以工作規則之約定代之", "勞動契約與團體協約之約定相異之部分，為該團體協約所不容許者，以勞動基準法之內容取代之", "團體協約居絕對有利地位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00465', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞資爭議處理法，下列何者能成為調整事項勞資爭議之勞方當事人？', '["已加入工會，但有勞工十人以上連署", "未加入工會，而具有相同主張之勞工達十人以上", "未依法登記為社團法人之勞工團體", "勞工未滿十人之事業單位，未加入工會之勞工具有相同主張者達二分之一以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00466', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '有關勞資爭議處理法之仲裁規定，下列何者正確？', '["一方申請交付仲裁者，可採獨任仲裁人方式為之", "仲裁委員會置委員三人至七人", "仲裁委員會應於收到事實調查結果後二十日內，作成仲裁判斷", "仲裁委員為事實調查之必要，得直接進入相關事業單位進行訪查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
